-- =====================================================================
-- SNA_Demo ONE-SHOT setup: paper-trader tables + roster + variant grid
-- Run ONCE in Supabase SQL editor (schema sifter_dev). Idempotent + re-runnable.
-- Supabase-safe: no apostrophes in comments, dollar-quoted JSONB, explicit columns.
-- Roster + variant tables are DROPPED and rebuilt (pure seed data, no user data).
-- =====================================================================

-- PART 0: drop seed/config tables so schema is always correct (safe: no live data)
DROP TABLE IF EXISTS sifter_dev.copy_wallets CASCADE;
DROP TABLE IF EXISTS sifter_dev.copy_clusters CASCADE;
DROP TABLE IF EXISTS sifter_dev.paper_variants CASCADE;

-- PART 1: paper-trade substrate (record-once tables; kept if they already hold data)
CREATE TABLE IF NOT EXISTS sifter_dev.paper_raw_cobuys (
  id BIGSERIAL PRIMARY KEY, ts TIMESTAMPTZ NOT NULL, wallet TEXT NOT NULL,
  wallet_tier TEXT, entry_style TEXT, token_address TEXT NOT NULL,
  trigger_price NUMERIC NOT NULL, security_pass BOOLEAN, created_at TIMESTAMPTZ DEFAULT NOW());
CREATE INDEX IF NOT EXISTS idx_raw_cobuys_token_ts ON sifter_dev.paper_raw_cobuys(token_address, ts);

CREATE TABLE IF NOT EXISTS sifter_dev.paper_price_paths (
  token_address TEXT NOT NULL, ts TIMESTAMPTZ NOT NULL, price NUMERIC NOT NULL,
  PRIMARY KEY (token_address, ts));

-- PART 2: variant grid (score-many)
CREATE TABLE sifter_dev.paper_variants (
  variant_id TEXT PRIMARY KEY, family TEXT NOT NULL, config JSONB NOT NULL);
CREATE TABLE IF NOT EXISTS sifter_dev.paper_variant_signals (
  id BIGSERIAL PRIMARY KEY, variant_id TEXT REFERENCES sifter_dev.paper_variants(variant_id),
  token_address TEXT NOT NULL, fired_ts TIMESTAMPTZ NOT NULL, entry_price NUMERIC,
  aborted BOOLEAN DEFAULT FALSE, exit_price NUMERIC, is_runner BOOLEAN, realized_roi NUMERIC,
  edge_kept NUMERIC, raw_event_id BIGINT REFERENCES sifter_dev.paper_raw_cobuys(id));
CREATE INDEX IF NOT EXISTS idx_variant_signals_vid ON sifter_dev.paper_variant_signals(variant_id);

-- PART 3: roster tables
CREATE TABLE sifter_dev.copy_wallets (
  address TEXT PRIMARY KEY, tier TEXT, role TEXT, runner_rate_pct NUMERIC,
  nonrunner_ev_pct NUMERIC, profit_factor NUMERIC, runner_to_ath_x NUMERIC,
  tokens_30d INT, entry_style TEXT, signal_strength TEXT, selectable BOOLEAN);
CREATE TABLE sifter_dev.copy_clusters (
  cluster_id TEXT PRIMARY KEY, is_bot_cluster BOOLEAN, members JSONB,
  shrunk_runner_rate_pct NUMERIC, nonrunner_ev_pct NUMERIC, signals_per_day NUMERIC,
  strength TEXT, co_entry_window_s INT DEFAULT 120, min_members_to_fire INT DEFAULT 2);

